import{_ as r,C as n,o as a,c as o,a2 as s,b as c,w as i,a as d,E as l,a3 as p}from"./chunks/framework.CkslIjGF.js";const F=JSON.parse('{"title":"Certificados e mTLS","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/certificates.md","filePath":"concepts/certificates.md"}'),h={name:"concepts/certificates.md"};function k(u,e,m,C,g,f){const t=n("Mermaid");return a(),o("div",null,[e[1]||(e[1]=s('<h1 id="certificados-e-mtls" tabindex="-1">Certificados e mTLS <a class="header-anchor" href="#certificados-e-mtls" aria-label="Permalink to &quot;Certificados e mTLS&quot;">​</a></h1><h2 id="por-que-certificados" tabindex="-1">Por que Certificados? <a class="header-anchor" href="#por-que-certificados" aria-label="Permalink to &quot;Por que Certificados?&quot;">​</a></h2><p>O Torukr usa <strong>mutual TLS (mTLS)</strong> para autenticar e criptografar a comunicação entre o Controller e cada NodeRuntime. Sem mTLS, qualquer processo na rede poderia fingir ser um NodeRuntime e receber instruções do Controller.</p><h2 id="hierarquia-de-certificados" tabindex="-1">Hierarquia de Certificados <a class="header-anchor" href="#hierarquia-de-certificados" aria-label="Permalink to &quot;Hierarquia de Certificados&quot;">​</a></h2>',4)),(a(),c(p,null,{default:i(()=>[l(t,{id:"mermaid-12",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20CA%5BCA%20-%20ca-cert.pem%5Cn%F0%9F%94%91%20ca-key.pem%5D%0A%20%20%20%20Server%5BNodeRuntime%5Cnserver-cert.pem%5Cn%F0%9F%94%91%20server-key.pem%5D%0A%20%20%20%20Client%5BController%5Cnclient-cert.pem%5Cn%F0%9F%94%91%20client-key.pem%5D%0A%0A%20%20%20%20CA%20--%3E%7Cassina%7C%20Server%0A%20%20%20%20CA%20--%3E%7Cassina%7C%20Client%0A"})]),fallback:i(()=>[...e[0]||(e[0]=[d(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=s(`<h2 id="certificados-gerados-pelo-gencerts" tabindex="-1">Certificados Gerados pelo <code>gencerts</code> <a class="header-anchor" href="#certificados-gerados-pelo-gencerts" aria-label="Permalink to &quot;Certificados Gerados pelo \`gencerts\`&quot;">​</a></h2><p>O binário <code>cmd/gencerts</code> gera três pares de certificado/chave:</p><table tabindex="0"><thead><tr><th>Arquivo</th><th>Uso</th></tr></thead><tbody><tr><td><code>ca-cert.pem</code></td><td>Certificado da CA raiz (distribuído para todos)</td></tr><tr><td><code>ca-key.pem</code></td><td>Chave privada da CA (<strong>manter seguro, nunca distribuir</strong>)</td></tr><tr><td><code>server-cert.pem</code></td><td>Certificado do NodeRuntime</td></tr><tr><td><code>server-key.pem</code></td><td>Chave privada do NodeRuntime</td></tr><tr><td><code>client-cert.pem</code></td><td>Certificado do Controller</td></tr><tr><td><code>client-key.pem</code></td><td>Chave privada do Controller</td></tr></tbody></table><h3 id="detalhes-do-certificado-de-servidor" tabindex="-1">Detalhes do Certificado de Servidor <a class="header-anchor" href="#detalhes-do-certificado-de-servidor" aria-label="Permalink to &quot;Detalhes do Certificado de Servidor&quot;">​</a></h3><ul><li><strong>Common Name</strong>: <code>noderuntime</code></li><li><strong>SANs</strong>: <code>localhost</code>, <code>noderuntime</code>, <code>noderuntime.torukr.svc</code></li><li>Usado pelo: NodeRuntime (apresenta este cert ao Controller)</li></ul><h3 id="detalhes-do-certificado-de-cliente" tabindex="-1">Detalhes do Certificado de Cliente <a class="header-anchor" href="#detalhes-do-certificado-de-cliente" aria-label="Permalink to &quot;Detalhes do Certificado de Cliente&quot;">​</a></h3><ul><li><strong>Common Name</strong>: <code>controller</code></li><li><strong>SANs</strong>: <code>controller</code>, <code>controller.torukr.svc</code></li><li>Usado pelo: Controller (apresenta este cert ao NodeRuntime)</li></ul><h2 id="gerar-certificados" tabindex="-1">Gerar Certificados <a class="header-anchor" href="#gerar-certificados" aria-label="Permalink to &quot;Gerar Certificados&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Gerar no diretório ./certs (padrão)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cmd/gencerts/main.go</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Especificar diretório</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cmd/gencerts/main.go</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/torukr/certs</span></span></code></pre></div><p>Saída esperada:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔐 Generating TLS certificates for Torukr...</span></span>
<span class="line"><span>Output directory: ./certs</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Generating CA certificate...</span></span>
<span class="line"><span>2. Generating NodeRuntime server certificate...</span></span>
<span class="line"><span>3. Generating Controller client certificate...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✅ Certificate generation complete!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Generated files:</span></span>
<span class="line"><span>  📄 CA Certificate:      ./certs/ca-cert.pem</span></span>
<span class="line"><span>  🔑 CA Key:              ./certs/ca-key.pem</span></span>
<span class="line"><span>  📄 Server Certificate:  ./certs/server-cert.pem</span></span>
<span class="line"><span>  🔑 Server Key:          ./certs/server-key.pem</span></span>
<span class="line"><span>  📄 Client Certificate:  ./certs/client-cert.pem</span></span>
<span class="line"><span>  🔑 Client Key:          ./certs/client-key.pem</span></span></code></pre></div><h2 id="configurar-os-certificados" tabindex="-1">Configurar os Certificados <a class="header-anchor" href="#configurar-os-certificados" aria-label="Permalink to &quot;Configurar os Certificados&quot;">​</a></h2><p>No arquivo <code>.env</code>:</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TORUKR_TLS_ENABLED</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TORUKR_TLS_CA_CERT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=./certs/ca-cert.pem</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TORUKR_TLS_SERVER_CERT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=./certs/server-cert.pem</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TORUKR_TLS_SERVER_KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=./certs/server-key.pem</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TORUKR_TLS_CLIENT_CERT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=./certs/client-cert.pem</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TORUKR_TLS_CLIENT_KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=./certs/client-key.pem</span></span></code></pre></div><h3 id="configuracao-dos-componentes" tabindex="-1">Configuração dos Componentes <a class="header-anchor" href="#configuracao-dos-componentes" aria-label="Permalink to &quot;Configuração dos Componentes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Componente</th><th>Certificados Necessários</th></tr></thead><tbody><tr><td><strong>NodeRuntime</strong></td><td><code>ca-cert.pem</code>, <code>server-cert.pem</code>, <code>server-key.pem</code></td></tr><tr><td><strong>Controller</strong></td><td><code>ca-cert.pem</code>, <code>client-cert.pem</code>, <code>client-key.pem</code></td></tr><tr><td><strong>API Server</strong></td><td>Não usa mTLS (usa JWT para autenticação)</td></tr></tbody></table><h2 id="verificar-certificados" tabindex="-1">Verificar Certificados <a class="header-anchor" href="#verificar-certificados" aria-label="Permalink to &quot;Verificar Certificados&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ver conteúdo do certificado CA</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> x509</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> certs/ca-cert.pem</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -text</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -noout</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Verificar que o servidor cert foi assinado pela CA</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> verify</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -CAfile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> certs/ca-cert.pem</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> certs/server-cert.pem</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Testar conexão mTLS com o NodeRuntime</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cacert</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./certs/ca-cert.pem</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">     --cert</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./certs/client-cert.pem</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">     --key</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./certs/client-key.pem</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     https://localhost:9090/runtime/v1/healthz</span></span></code></pre></div><h2 id="modo-desenvolvimento-inseguro" tabindex="-1">Modo Desenvolvimento (Inseguro) <a class="header-anchor" href="#modo-desenvolvimento-inseguro" aria-label="Permalink to &quot;Modo Desenvolvimento (Inseguro)&quot;">​</a></h2><p>Para desenvolvimento, você pode desabilitar a verificação de certificados:</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TORUKR_TLS_INSECURE_SKIP_VERIFY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>Nunca use <code>INSECURE_SKIP_VERIFY=true</code> em produção. Isso elimina toda a proteção do mTLS.</p></div><h2 id="rotacao-de-certificados" tabindex="-1">Rotação de Certificados <a class="header-anchor" href="#rotacao-de-certificados" aria-label="Permalink to &quot;Rotação de Certificados&quot;">​</a></h2><p>Veja o <a href="/tutorials/rotate-certificates.html">Tutorial de Rotação de Certificados</a> para o procedimento completo.</p><p>Resumo:</p><ol><li>Gerar novos certificados com <code>gencerts</code></li><li>Distribuir para os nodes</li><li>Reiniciar NodeRuntime e Controller</li><li>Verificar conectividade</li></ol><h2 id="boas-praticas" tabindex="-1">Boas Práticas <a class="header-anchor" href="#boas-praticas" aria-label="Permalink to &quot;Boas Práticas&quot;">​</a></h2><ul><li>Mantenha <code>ca-key.pem</code>, <code>server-key.pem</code> e <code>client-key.pem</code> com permissão <code>600</code></li><li>Adicione <code>*.pem</code> ao <code>.gitignore</code></li><li>Rotacione certificados a cada 12 meses em produção</li><li>Em multi-node, copie apenas <code>ca-cert.pem</code>, <code>server-cert.pem</code>, <code>server-key.pem</code> para cada node worker</li></ul><h2 id="erros-comuns" tabindex="-1">Erros Comuns <a class="header-anchor" href="#erros-comuns" aria-label="Permalink to &quot;Erros Comuns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Erro</th><th>Causa</th><th>Solução</th></tr></thead><tbody><tr><td><code>certificate signed by unknown authority</code></td><td>CA incorreta</td><td>Verificar <code>TORUKR_TLS_CA_CERT</code></td></tr><tr><td><code>tls: bad certificate</code></td><td>Cert do cliente rejeitado</td><td>Verificar que o cert cliente foi assinado pela mesma CA</td></tr><tr><td><code>connection refused</code></td><td>NodeRuntime não está rodando</td><td>Verificar porta 9090</td></tr><tr><td><code>tls: no certificates configured</code></td><td>Variáveis TLS não configuradas</td><td>Verificar o <code>.env</code></td></tr></tbody></table><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><ul><li><a href="/setup/generate-certificates.html">Tutorial: Gerar Certificados</a></li><li><a href="/tutorials/rotate-certificates.html">Tutorial: Rotacionar Certificados</a></li><li><a href="/concepts/security.html">Segurança</a></li></ul>`,32))])}const b=r(h,[["render",k]]);export{F as __pageData,b as default};
